@using sv_b8ba745bdd0540769563d37affc48097.Models
@inject ISettingsService SettingsService

<div class="profile-section">
    @if (_loading)
    {
        <div class="text-center p-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="mb-4">Profile Settings</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <label class="form-label fw-semibold d-block">Avatar Preview</label>
                    <div class="avatar-frame mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <small class="text-muted text-break">@_avatarUrl</small>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid var(--bs-border-color, #dee2e6);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background-color: var(--bs-tertiary-bg, #f8f9fa);
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
    color: var(--bs-secondary-color, #6c757d);
}

@using sv_b8ba745bdd0540769563d37affc48097.Models
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <div class="text-center p-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="mb-4">Notification Preferences</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (_allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox"
                               id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
            _allChannels = new List<string>(prefs.MutedChannels);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_b8ba745bdd0540769563d37affc48097.Models
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <div class="text-center p-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="mb-4">Security Settings</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex align-items-center justify-content-between"
                 role="button" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <h6 class="fw-semibold mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           id="twoFactor" @bind="_twoFactorEnabled" />
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @if (_sessions.Count == 0)
                            {
                                <tr>
                                    <td colspan="4" class="text-center text-muted py-3">No active sessions.</td>
                                </tr>
                            }
                            else
                            {
                                @foreach (var session in _sessions)
                                {
                                    var isCurrent = session == _sessions[0];
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrent)
                                            {
                                                <span class="badge bg-primary ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("g")</td>
                                        <td>
                                            @if (!isCurrent)
                                            {
                                                <button class="btn btn-outline-danger btn-sm"
                                                        @onclick="() => PromptRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted mb-0">This will sign the device out immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private string? _message;
    private bool _messageIsError;

    // Password
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;

    // 2FA
    private bool _twoFactorEnabled;

    // Sessions
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _sessions = settings.Sessions.ToList();
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password cannot be empty.";
            _messageIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _messageIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _messageIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordExpanded = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _message = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _messageIsError = false;
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _revoking = false;
        }
    }
}

