            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="mb-4">Profile Settings</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <label class="form-label fw-semibold d-block">Avatar Preview</label>
                    <div class="avatar-frame mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <small class="text-muted text-break">@_avatarUrl</small>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

