toolArgs.file_text:
.preview-area {
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid inherit;
}

.preview-body {
    padding: 1rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid inherit;
}

.preview-button {
    padding: 0.375rem 0.75rem;
    border-radius: 0.25rem;
    border: 1px solid transparent;
    cursor: pointer;
    font: inherit;
}

/* Theme variants */
.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background-color: #f8f9fa;
    border-color: #dee2e6;
}

.preview-light .preview-footer {
    background-color: #f8f9fa;
    border-color: #dee2e6;
}

.preview-light .preview-button {
    background-color: #0d6efd;
    color: #fff;
}

.preview-dark {
    background-color: #1e1e2e;
    color: #e0e0e0;
}

.preview-dark .preview-header {
    background-color: #2a2a3d;
    border-color: #3a3a4d;
}

.preview-dark .preview-footer {
    background-color: #2a2a3d;
    border-color: #3a3a4d;
}

.preview-dark .preview-button {
    background-color: #6c8cff;
    color: #fff;
}

/* Font sizes */
.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header,
.preview-compact .preview-footer {
    padding: 0.35rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-body p {
    margin-bottom: 0.25rem;
}

